@page "/dispatcher"
@using Microsoft.AspNetCore.Authorization
@attribute [Authorize]
@inject IShipmentService ShipmentService

<PageTitle>Dispatcher Dashboard</PageTitle>

<h1>Dispatcher Dashboard</h1>

@if (shipments is null)
{
    <p><em>Loading shipments...</em></p>
}
else
{
    <div class="mb-3">
        <label for="statusFilter" class="form-label">Filter by Status:</label>
        <select id="statusFilter" class="form-select w-auto" @bind="selectedFilter">
            <option value="">All</option>
            @foreach (var status in Enum.GetValues<ShipmentStatus>())
            {
                <option value="@status">@status</option>
            }
        </select>
    </div>

    <table class="table table-striped">
        <thead>
            <tr>
                <th>Tracking #</th>
                <th>Origin</th>
                <th>Destination</th>
                <th>Status</th>
                <th>Shipped Date</th>
                <th>Est. Delivery</th>
                <th>Actions</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var shipment in FilteredShipments)
            {
                <tr>
                    <td>@shipment.TrackingNumber</td>
                    <td>@shipment.Origin</td>
                    <td>@shipment.Destination</td>
                    <td><span class="badge @GetStatusBadgeClass(shipment.Status)">@shipment.Status</span></td>
                    <td>@shipment.ShippedDate.ToString("yyyy-MM-dd")</td>
                    <td>@shipment.EstimatedDelivery.ToString("yyyy-MM-dd")</td>
                    <td>
                        <div class="d-flex gap-1">
                            <select class="form-select form-select-sm w-auto" @bind="statusUpdates[shipment.Id]">
                                @foreach (var status in Enum.GetValues<ShipmentStatus>())
                                {
                                    <option value="@status">@status</option>
                                }
                            </select>
                            <button class="btn btn-sm btn-primary" @onclick="() => UpdateStatus(shipment)">Update</button>
                        </div>
                    </td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    private List<Shipment>? shipments;
    private string selectedFilter = "";
    private Dictionary<int, ShipmentStatus> statusUpdates = new();

    private IEnumerable<Shipment> FilteredShipments =>
        string.IsNullOrEmpty(selectedFilter)
            ? shipments!
            : shipments!.Where(s => s.Status.ToString() == selectedFilter);

    protected override async Task OnInitializedAsync()
    {
        shipments = await ShipmentService.GetAllShipmentsAsync();
        foreach (var s in shipments)
        {
            statusUpdates[s.Id] = s.Status;
        }
    }

    private async Task UpdateStatus(Shipment shipment)
    {
        var newStatus = statusUpdates[shipment.Id];
        var updated = await ShipmentService.UpdateStatusAsync(shipment.Id, newStatus);
        if (updated is not null)
        {
            shipment.Status = updated.Status;
        }
    }

    private static string GetStatusBadgeClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => "bg-secondary",
        ShipmentStatus.PickedUp => "bg-info",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.OutForDelivery => "bg-warning text-dark",
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.Delayed => "bg-danger",
        _ => "bg-secondary"
    };
}

@page "/track"
@inject IShipmentService ShipmentService

<PageTitle>Track Shipment</PageTitle>

<h1>Track Your Shipment</h1>

<div class="mb-3 d-flex gap-2">
    <input type="text" class="form-control w-auto" placeholder="Enter tracking number" @bind="trackingNumber" @bind:event="oninput" @onkeydown="HandleKeyDown" />
    <button class="btn btn-primary" @onclick="TrackShipment" disabled="@isLoading">
        @if (isLoading)
        {
            <span class="spinner-border spinner-border-sm" role="status" aria-hidden="true"></span>
        }
        else
        {
            <span>Track</span>
        }
    </button>
</div>

@if (searched && shipment is null)
{
    <div class="alert alert-warning">
        No shipment found with tracking number "<strong>@searchedNumber</strong>".
    </div>
}
else if (shipment is not null)
{
    <div class="card" style="max-width: 500px;">
        <div class="card-header">
            <strong>@shipment.TrackingNumber</strong>
            <span class="badge @GetStatusBadgeClass(shipment.Status) ms-2">@shipment.Status</span>
        </div>
        <div class="card-body">
            <p><strong>Description:</strong> @shipment.Description</p>
            <p><strong>Origin:</strong> @shipment.Origin</p>
            <p><strong>Destination:</strong> @shipment.Destination</p>
            <p><strong>Shipped Date:</strong> @shipment.ShippedDate.ToString("yyyy-MM-dd")</p>
            <p><strong>Estimated Delivery:</strong> @shipment.EstimatedDelivery.ToString("yyyy-MM-dd")</p>
        </div>
    </div>
}

@code {
    private string trackingNumber = "";
    private string searchedNumber = "";
    private Shipment? shipment;
    private bool searched;
    private bool isLoading;

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (e.Key == "Enter")
        {
            await TrackShipment();
        }
    }

    private async Task TrackShipment()
    {
        if (string.IsNullOrWhiteSpace(trackingNumber))
            return;

        isLoading = true;
        searchedNumber = trackingNumber.Trim();
        shipment = await ShipmentService.GetByTrackingNumberAsync(searchedNumber);
        searched = true;
        isLoading = false;
    }

    private static string GetStatusBadgeClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => "bg-secondary",
        ShipmentStatus.PickedUp => "bg-info",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.OutForDelivery => "bg-warning text-dark",
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.Delayed => "bg-danger",
        _ => "bg-secondary"
    };
}

