 @page "/dispatcher"
 @using Microsoft.AspNetCore.Authorization
 @attribute [Authorize]
 @inject IShipmentService ShipmentService

 <PageTitle>Dispatcher Dashboard</PageTitle>

 <h1>Dispatcher Dashboard</h1>

 @if (shipments is null)
 {
     <p><em>Loading shipments...</em></p>
 }
 else
 {
     <div class="mb-3">
         <label for="statusFilter" class="form-label">Filter by Status:</label>
         <select id="statusFilter" class="form-select w-auto" @bind="selectedFilter">
             <option value="">All</option>
             @foreach (var status in Enum.GetValues<ShipmentStatus>())
             {
                 <option value="@status">@status</option>
             }
         </select>
     </div>

     <table class="table table-striped">
         <thead>
             <tr>
                 <th>Tracking #</th>
                 <th>Origin</th>
                 <th>Destination</th>
                 <th>Status</th>
                 <th>Shipped Date</th>
                 <th>Est. Delivery</th>
                 <th>Actions</th>
             </tr>
         </thead>
         <tbody>
             @foreach (var shipment in FilteredShipments)
             {
                 <tr>
                     <td>@shipment.TrackingNumber</td>
                     <td>@shipment.Origin</td>
                     <td>@shipment.Destination</td>
                     <td><span class="badge @GetStatusBadgeClass(shipment.Status)">@shipment.Status</span></td>
                     <td>@shipment.ShippedDate.ToString("yyyy-MM-dd")</td>
                     <td>@shipment.EstimatedDelivery.ToString("yyyy-MM-dd")</td>
                     <td>
                         <div class="d-flex gap-1">
                             <select class="form-select form-select-sm w-auto" @bind="statusUpdates[shipment.Id]">
                                 @foreach (var status in Enum.GetValues<ShipmentStatus>())
                                 {
                                     <option value="@status">@status</option>
                                 }
                             </select>
                             <button class="btn btn-sm btn-primary" @onclick="() => UpdateStatus(shipment)">Update</button>
                         </div>
                     </td>
                 </tr>
             }
         </tbody>
